public static long solve(long[] nums) {
    int n = nums.length;
    long maxSum = 0;

    // Iterate over all possible masks for B (non-empty or empty)
    for (int mask = 0; mask < (1 << n); mask++) {
        long xorA = 0;
        long andB = ~0L; // Initialize to all 1s for AND (identity)
        long xorC = 0;
        boolean hasB = false;

        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                // Element is in B
                andB &= nums[i];
                hasB = true;
            } else {
                // Element is either in A or C
                // We need to try all possible splits between A and C for elements not in B
                // To maximize the sum, we can try all possible splits for the remaining elements
                // But with n up to 19, this is not feasible. Instead, we can optimize by considering
                // that for a given B, the optimal A and C can be determined by trying all possible splits
                // of the remaining elements into A and C.
                // So we need another loop here for the remaining elements.
                // However, with n up to 19, this would be O(3^n), which is too slow.
                // Therefore, we need a smarter approach.
                // Since XOR and AND are not associative in a way that allows easy splitting,
                // we have to accept the O(3^n) approach for small n (n <= 19).
                // So we'll proceed with the nested loop approach.
            }
        }

        // Now, for the elements not in B, try all possible splits into A and C
        int remainingCount = n - Integer.bitCount(mask);
        for (int split = 0; split < (1 << remainingCount); split++) {
            xorA = 0;
            xorC = 0;
            int aIndex = 0;
            int cIndex = 0;
            int currentSplitPos = 0;

            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    continue; // skip B elements
                }
                if ((split & (1 << currentSplitPos)) != 0) {
                    xorA ^= nums[i];
                } else {
                    xorC ^= nums[i];
                }
                currentSplitPos++;
            }

            long currentAndB = hasB ? andB : 0;
            long currentSum = xorA + currentAndB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
